oxy_webhelp_navlinks = {"k8s_vm_recovery_live_mount-d26997e20581":{"topics":[{"title":"Prerequisites for OpenShift virtual machine Live Mount","shortdesc":"<p class=\"shortdesc\">Before creating a Live Mount, ensure the Kubernetes cluster environment is configured         to support network file system, specific version requirements, and the required volume         types.<\/p>","href":"kubernetes\/k8s_prereqs_openshift_vm_live_mount.html","attributes":{"data-id":"k8s_prereqs_openshift_vm_live_mount"},"menu":{"hasChildren":false},"tocID":"k8s_prereqs_openshift_vm_live_mount-d26997e20594","topics":[]},{"title":"Creating a Live Mount for OpenShift virtual machines","shortdesc":"<p class=\"shortdesc\">Create a Live Mount for an OpenShift virtual machine on a Kubernetes cluster from a         snapshot on the Rubrik cluster. The live mounted virtual machine uses the Rubrik cluster as         its underlying storage.<\/p>","href":"kubernetes\/k8s_creating_live_mount.html","attributes":{"data-id":"k8s_creating_live_mount"},"menu":{"hasChildren":false},"tocID":"k8s_creating_live_mount-d26997e20605","topics":[]},{"title":"Unmounting an OpenShift virtual machine","shortdesc":"<p class=\"shortdesc\">Unmount a recovered OpenShift virtual machine from <span class=\"ph\">RSC<\/span>.<\/p>","href":"kubernetes\/k8s_unmounting_vm.html","attributes":{"data-id":"k8s_unmounting_vm"},"menu":{"hasChildren":false},"tocID":"k8s_unmounting_vm-d26997e20616","topics":[]},{"title":"Unmount behavior for OpenShift virtual machines","shortdesc":"<p class=\"shortdesc\">Unmount a Live Mount to end the recovery session and clean up Rubrik-hosted         resources. The final state of the virtual machine depends on its storage status and whether         a storage migration occurred during the session.<\/p>","href":"kubernetes\/k8s_unmount_behavior_openshift_vms.html","attributes":{"data-id":"k8s_unmount_behavior_openshift_vms"},"menu":{"hasChildren":false},"tocID":"k8s_unmount_behavior_openshift_vms-d26997e20630","topics":[]},{"title":"NFS client IP configuration","shortdesc":"<p class=\"shortdesc\">Rubrik uses specific IP addresses from Kubernetes nodes to expose NFS shares during a Live Mount operation.<\/p>","href":"kubernetes\/k8s_nfs_ip_configuration.html","attributes":{"data-id":"k8s_nfs_ip_configuration"},"menu":{"hasChildren":false},"tocID":"k8s_nfs_ip_configuration-d26997e20641","topics":[]}]}};